node Tag { has text: str; }

walker JoinTags {
    has joined: str = "";
    can read with Tag entry {
        if self.joined == "" { self.joined = here.text; }
        else { self.joined = self.joined + "-" + here.text; }
        visit [-->];
    }
}

def join_chain_labels(spec: dict) -> str {
    labels: list = list(spec["labels"]);
    if not labels { return ""; }
    head = Tag(text=str(labels[0]));
    prev = head;
    for lb in labels[1:] {
        nxt = Tag(text=str(lb));
        prev ++> nxt;
        prev = nxt;
    }
    return (head spawn JoinTags()).joined;
}

with entry { print(join_chain_labels({"labels": ["red", "green", "blue"]})); }

walker AltSum { has balance: int = 0; has flip: int = 1; }

node Beat {
    has amt: int;
    can strike with AltSum entry {
        visitor.balance += visitor.flip * self.amt;
        visitor.flip = -visitor.flip;
        visit [-->];
    }
}

def alternating_chain_sum(spec: dict) -> int {
    beats: list = [Beat(amt=int(v)) for v in spec["nums"]];
    if not beats { return 0; }
    for (x, y) in zip(beats, beats[1:]) { x ++> y; }
    return (beats[0] spawn AltSum()).balance;
}

with entry { print(alternating_chain_sum({"nums": [10, 3, 2]})); }

walker Doubler { has picked: list = []; }

node Slot {
    has q: int;
    can serve with Doubler entry {
        visitor.picked.append(self.q * 2);
        visit [-->];
    }
}

def doubled_chain_values(spec: dict) -> list {
    slots: list = [];
    for raw in spec["values"] {
        cell = Slot(q=int(raw));
        slots.append(cell);
        if len(slots) > 1 { slots[-2] ++> cell; }
    }
    if not slots { return []; }
    runner = slots[0] spawn Doubler();
    return runner.picked;
}

with entry { print(doubled_chain_values({"values": [3, 1, 4]})); }

node Card { has word: str; }

walker LenCount {
    has chars: int = 0;
    can weigh with Card entry { self.chars += len(here.word); visit [-->]; }
}

def link_cards(words: list, at: int) -> Card {
    c = Card(word=str(words[at]));
    if at + 1 < len(words) { c ++> link_cards(words, at + 1); }
    return c;
}

def total_label_length(spec: dict) -> int {
    if not spec["words"] { return 0; }
    head = link_cards(list(spec["words"]), 0);
    counter = head spawn LenCount();
    return counter.chars;
}

with entry { print(total_label_length({"words": ["hi", "there"]})); }

