node Stop { has name: str; }

walker Tracer {
    has path: list = [];
    can log with Stop entry { self.path.append(here.name); visit [-->]; }
}

def trace_route(spec: dict) -> str {
    nxt: dict = dict(spec["next"]);
    cur: str = str(spec["start"]);
    first = Stop(name=cur);
    tip = first;
    while nxt.get(cur, "") != "" {
        cur = str(nxt[cur]);
        hop = Stop(name=cur);
        tip ++> hop;
        tip = hop;
    }
    return "/".join((first spawn Tracer()).path);
}

with entry { print(trace_route({"next": {"dock": "gate", "gate": "hall", "hall": ""}, "start": "dock"})); }

walker LevelPick { has bag: list = []; }

node Meter {
    has level: float;
    has done: bool = False;
    can share with LevelPick entry {
        if not self.done {
            self.done = True;
            visitor.bag.append(self.level);
            visit [-->];
        }
    }
}

def sorted_reachable_vals(spec: dict) -> list {
    meters: dict = {k: Meter(level=float(v)) for (k, v) in spec["vals"].items()};
    for (frm, tos) in spec["adj"].items() {
        for t in tos { meters[frm] ++> meters[t]; }
    }
    picker = meters[str(spec["start"])] spawn LevelPick();
    return sorted(picker.bag);
}

with entry { print(sorted_reachable_vals({"adj": {"a": ["b", "c"], "b": ["d"], "c": ["d"], "d": []}, "vals": {"a": 1.5, "b": 0.25, "c": 3.0, "d": 2.5}, "start": "a"})); }

node Rung { has load: int; }

walker DepthSum {
    has acc: int = 0;
    has rung_no: int = 0;
    can climb with Rung entry {
        self.rung_no += 1;
        self.acc += here.load * self.rung_no;
        visit [-->];
    }
}

def position_weighted_sum(spec: dict) -> int {
    tail = None;
    for n in reversed(spec["nums"]) {
        rung = Rung(load=int(n));
        if tail is not None { rung ++> tail; }
        tail = rung;
    }
    if tail is None { return 0; }
    climber = tail spawn DepthSum();
    return climber.acc;
}

with entry { print(position_weighted_sum({"nums": [2, 3, 4]})); }

node Site { has tag: str; has hit: bool = False; }

walker TagPick {
    has tags: list = [];
    can mark with Site entry {
        if not here.hit {
            here.hit = True;
            self.tags.append(here.tag);
            visit [-->];
        }
    }
}

def sorted_label_csv(spec: dict) -> str {
    sites: dict = {};
    for (origin, outs) in spec["adj"].items() {
        if origin not in sites { sites[origin] = Site(tag=str(origin)); }
        for target in list(outs) {
            if target not in sites { sites[target] = Site(tag=str(target)); }
            sites[origin] ++> sites[target];
        }
    }
    entry_key: str = str(spec["start"]);
    crawler = sites[entry_key] spawn TagPick();
    return ",".join(sorted(crawler.tags));
}

with entry { print(sorted_label_csv({"adj": {"m": ["k", "z"], "k": [], "z": ["b"], "b": []}, "start": "m"})); }

node Post {}
edge TollGate { has fee: int; }

walker FeeProd {
    has prod: int = 1;
    can pay with TollGate entry { self.prod *= here.fee; }
    can advance with Post entry { visit [edge -->]; }
}

def edge_weight_product(spec: dict) -> int {
    tolls: list = list(spec["tolls"]);
    posts: list = [Post() for _ in range(len(tolls) + 1)];
    k: int = len(tolls);
    while k > 0 {
        posts[k - 1] +>:TollGate(fee=int(tolls[k - 1])):+> posts[k];
        k -= 1;
    }
    return (posts[0] spawn FeeProd()).prod;
}

with entry { print(edge_weight_product({"tolls": [2, 3, 4]})); }

