node Gauge { has v: int; }

walker PeakTrail {
    has trail: list = [];
    can note with Gauge entry {
        if not self.trail { self.trail.append(here.v); }
        elif here.v > self.trail[-1] { self.trail.append(here.v); }
        else { self.trail.append(self.trail[-1]); }
        visit [-->];
    }
}

def running_max_prefix(spec: dict) -> list {
    if len(spec["nums"]) == 0 { return []; }
    gauges: list = [Gauge(v=int(n)) for n in spec["nums"]];
    for i in range(1, len(gauges)) { gauges[i - 1] ++> gauges[i]; }
    hiker = gauges[0] spawn PeakTrail();
    return hiker.trail;
}

with entry { print(running_max_prefix({"nums": [3, 1, 4, 1, 5]})); }

node Sensor { has sid: str; has reading: int; }

walker AvgReader {
    has seen: list = [];
    has readings: list = [];
    has mean: float = 0.0;
    can poll with Sensor entry {
        if here.sid in self.seen { return; }
        self.seen.append(here.sid);
        self.readings.append(here.reading);
        visit [-->];
    }
    can wrap with exit {
        self.mean = round(sum(self.readings) / len(self.readings), 2);
    }
}

def mean_reachable_val(spec: dict) -> float {
    vals: dict = dict(spec["vals"]);
    adj: dict = dict(spec["adj"]);
    grid: dict = {};
    for sid in vals.keys() { grid[sid] = Sensor(sid=str(sid), reading=int(vals[sid])); }
    for a in adj.keys() {
        for b in adj[a] { grid[a] ++> grid[b]; }
    }
    return (grid[str(spec["start"])] spawn AvgReader()).mean;
}

with entry { print(mean_reachable_val({"adj": {"a": ["b", "c"], "b": [], "c": []}, "vals": {"a": 3, "b": 4, "c": 6}, "start": "a"})); }

node Town { has gain: int; }
edge Road { has toll: int; }

walker TripLedger {
    has bal: int = 0;
    can settle with Town entry {
        self.bal += here.gain;
        for e in [edge here -->] { self.bal -= e.toll; }
        visit [-->];
    }
}

def toll_trip_balance(spec: dict) -> int {
    towns: list = [Town(gain=int(g)) for g in spec["gains"]];
    for (i, fee) in enumerate(spec["tolls"]) {
        towns[i] +>:Road(toll=int(fee)):+> towns[i + 1];
    }
    ledger = towns[0] spawn TripLedger();
    return ledger.bal;
}

with entry { print(toll_trip_balance({"gains": [5, 3, 8], "tolls": [2, 4]})); }

node Page { has word: str; has taken: bool = False; }

walker InitialScan {
    has letters: list = [];
    has counts: list = [];
    can skim with Page entry {
        if here.taken { return; }
        here.taken = True;
        letter: str = here.word[0];
        if letter in self.letters {
            idx: int = self.letters.index(letter);
            self.counts[idx] += 1;
        } else {
            self.letters.append(letter);
            self.counts.append(1);
        }
        visit [-->];
    }
}

def label_initial_histogram(spec: dict) -> list {
    book: dict = {};
    for (nid, wd) in spec["labels"].items() { book[nid] = Page(word=str(wd)); }
    for a_id in spec["adj"] {
        for b_id in spec["adj"][a_id] { book[a_id] ++> book[b_id]; }
    }
    origin: str = str(spec["start"]);
    scanner = book[origin] spawn InitialScan();
    pairs: list = [];
    for (lt, ct) in zip(scanner.letters, scanner.counts) { pairs.append([lt, ct]); }
    pairs.sort();
    return pairs;
}

with entry { print(label_initial_histogram({"adj": {"n1": ["n2", "n3"], "n2": [], "n3": ["n4"], "n4": []}, "labels": {"n1": "apple", "n2": "ant", "n3": "berry", "n4": "avocado"}, "start": "n1"})); }

node Kiosk { has label: str; has cost: int; }

walker BudgetWalk {
    has budget: int = 0;
    has spent: int = 0;
    has names: list = [];
    can shop with Kiosk entry {
        if self.spent + here.cost > self.budget { disengage; }
        self.spent += here.cost;
        self.names.append(here.label);
        visit [-->];
    }
}

def budget_walk_labels(spec: dict) -> list {
    kiosks: list = [Kiosk(label=str(pr[0]), cost=int(pr[1])) for pr in spec["stops"]];
    if len(kiosks) == 0 { return []; }
    k: int = 0;
    while k + 1 < len(kiosks) { kiosks[k] ++> kiosks[k + 1]; k += 1; }
    shopper = kiosks[0] spawn BudgetWalk(budget=int(spec["budget"]));
    return shopper.names;
}

with entry { print(budget_walk_labels({"stops": [["a", 3], ["b", 4], ["c", 9], ["d", 1]], "budget": 8})); }
